mapper.select:
SELECT DISTINCT c.small_category AS value
FROM new_category c
WHERE c.large_category = #{largeCategory}
AND c.medium_category = #{mediumCategory}
ORDER BY c.small_category

SELECT DISTINCT e.expense_type AS value
FROM new_expense_info e INNER JOIN new_category c
ON c.id = e.category_id
WHERE c.large_category = #{largeCategory}
AND c.medium_category = #{mediumCategory}
AND c.small_category = #{smallCategory}
AND e.expense_type IS NOT NULL
ORDER BY e.expense_type

