mapper.select:
SELECT c.id
FROM new_category c
WHERE c.large_category = #{largeCategory}
AND c.medium_category = #{mediumCategory}
AND c.small_category = #{smallCategory}
LIMIT 1

SELECT COUNT(*)
FROM new_expense_info
WHERE expense_date = #{expenseDate}
AND total_cost = #{totalCost}


        AND expense_time = #{expenseTime}


        AND expense_time IS NULL

SELECT COUNT(*)
FROM new_expense_info
WHERE id != #{id}
AND expense_date = #{expenseDate}
AND total_cost = #{totalCost}


        AND expense_time = #{expenseTime}


        AND expense_time IS NULL

SELECT id
FROM new_expense_info
WHERE expense_date = #{expenseDate}
AND total_cost = #{totalCost}


        AND expense_time = #{expenseTime}


        AND expense_time IS NULL


ORDER BY id DESC
LIMIT 1
